import player_ss from './../image/player.png'
import background from './../image/background.png'

// グローバルに展開
phina.globalize()

const SCREEN_WIDTH = 640
const SCREEN_HEIGHT = 960
const PLAYER_POSITION = 800
const ASSETS = {
  image: {
    player: player_ss,
    background: background
  },
  spritesheet: {
    player_ss: {
      // フレーム情報
      frame: {
        width: 64, // 1フレームの画像サイズ（横）
        height: 64, // 1フレームの画像サイズ（縦）
        cols: 2, // フレーム数（横）
        rows: 1, // フレーム数（縦）
      },
      // アニメーション情報
      animations: {
        normal: {
          // アニメーション名
          frames: [1, 2], // フレーム番号範囲
          next: 'normal', // 次のアニメーション
          frequency: 5, // アニメーション間隔
        },
      },
    },
  },
}

/*
 * タイトル
 */
phina.define("Title", {
  superClass: 'DisplayScene',
  init: function() {
    // 親クラス初期化
    this.superInit();
    // 背景色
    this.backgroundColor = 'black';
    // ラベル
    Label({
      text: 'Title',
      fontSize: 48,
      fill: 'yellow',
    }).addChildTo(this).setPosition(this.gridX.center(), this.gridY.center());
  },
  // タッチで次のシーンへ
  onpointstart: function() {
    this.exit();
  },
});

/*
 * リザルト
 */
phina.define("Result", {
  superClass: 'DisplayScene',
  init: function(params) {
    // 親クラス初期化
    this.superInit(params);

    // ラベル
    Label({
      text: params.score,
      fontSize: 48,
      fill: 'black',
    }).addChildTo(this).setPosition(this.gridX.center(), this.gridY.center());


    const tweet = Button({text: "ツイート"})
      .setPosition(this.gridX.span(4), this.gridY.span(12))
      .addChildTo(this)
      .on('push', ()=> {
        const text = 'スコア: {0}\n{1}'.format(params.score, '牛を避けるゲーム');
        const url = phina.social.Twitter.createURL({
          text: text,
          hashtags: '牛を避けるだけのクソゲー',
          url: 'https://yoshinani.com/game/block_runner.html',
        });
        window.open(url, 'share window', 'width=480, height=320');
      });

    const play = Button({text: "プレイ"})
      .setPosition(this.gridX.span(12), this.gridY.span(12))
      .addChildTo(this)
      .on('push', ()=> {
        this.exit()
      });

  }
});

/*
 * メイン
 */
phina.define('Main', {
  superClass: 'DisplayScene',
  init: function() {
    this.superInit({
      width: SCREEN_WIDTH,
      height: SCREEN_HEIGHT,
    })

    // 背景
    Sprite('background').addChildTo(this).setPosition(this.gridX.center(), this.gridY.center());

    // スコア
    this.score = 0
    this.scoreLabel = Label(this.score).addChildTo(this)
    this.scoreLabel.x = this.gridX.center()
    this.scoreLabel.y = this.gridY.span(1)

    this.bombGroup = DisplayElement().addChildTo(this)

    // プレイヤー
    this.player = Sprite('player', 64, 64).addChildTo(this)
    this.player.setPosition(320, PLAYER_POSITION)
  },
  // 毎フレーム更新処理
  update(app) {
    const p = app.pointer
    if (p.getPointing()) {
      if (p.x < 0) {
        this.player.setPosition(0, PLAYER_POSITION)
      } else if (p.x > 640) {
        this.player.setPosition(640, PLAYER_POSITION)
      } else {
        this.player.setPosition(p.x, PLAYER_POSITION)
      }
    }

    this.bombGroup.children.forEach(
      function (bomb) {
        if (this.height < bomb.y) {
          this.score += 1
          this.scoreLabel.text = this.score
          bomb.remove()
        }
        if (this.player.hitTestElement(bomb)) {
          this.gameover()
        }
      }.bind(this)
    )

    if (app.frame % 5 === 0) {
      this.spawnBomb()
    }
  },
  // 爆弾スポーン
  spawnBomb() {
    const x = Math.randint(0, this.width)
    const y = -100
    Bomb(x, y).addChildTo(this.bombGroup)
  },
  // ゲームオーバー
  gameover() {
    this.exit({
      score: this.score,
    })
  },
})

/*
 * 爆弾
 */
phina.define('Bomb', {
  superClass: 'Shape',

  init(x, y) {
    this.superInit()
    const randomWidth = Math.randint(20, 100)
    this.width = randomWidth
    this.height = 20
    this.backgroundColor = 'black'
    const randomAccel = Math.randint(10, 80)
    this.accel = randomAccel
    this.setPosition(x, y)
  },

  update() {
    this.y += this.accel
  },
})

/*
 * メイン処理
 */
phina.main(function () {
  // アプリケーションを生成
  const app = GameApp({
    startLabel: 'title',
    title: 'クソゲー',
    width: SCREEN_WIDTH,
    height: SCREEN_HEIGHT,
    assets: ASSETS,
    debug: false,
    startLabel: 'Title',
    scenes: [
      {
        className: 'Title',
        label: 'Title',
        nextLabel: 'Main',
      },
      {
        className: 'Main',
        label: 'Main',
        nextLabel: 'Result',
      },
      {
        className: 'Result',
        label: 'Result',
        nextLabel: 'Main',
      },
    ]
  })
  // 実行
  app.run()
})
